def solve(nums : Array(Int64)) : Int64
    n = nums.length
    indices_1 = Array(Int32)
    indices_2 = Array(Int32)

    # Collect indices where nums[i] is 1 or 2
    for i in 0...n {
        if nums[i] == 1 {
            indices_1.push(i.to_int32)
        } else if nums[i] == 2 {
            indices_2.push(i.to_int32)
        }
    }

    # If either type is missing, no valid pair exists
    if indices_1.empty? || indices_2.empty? {
        return -1_i64
    }

    # Initialize minimum difference to a very large value
    min_diff = Int32.max

    # Iterate over all pairs (i, j)
    for i_idx in indices_1 {
        for j_idx in indices_2 {
            # Calculate absolute difference: |i_idx - j_idx|
            diff = i_idx - j_idx
            abs_diff = diff.abs

            if abs_diff < min_diff {
                min_diff = abs_diff
            }
        }
    }

    # Return the minimum difference as Int64
    return min_diff.to_i64
end
